defmodule SessionPlug do
  @moduledoc """
  A Plug that integrates SessionManager with Phoenix/Plug pipelines.
  Reads session from a cookie, deserializes it, and makes it available
  in conn.assigns. Serializes the session back to a cookie on response.
  """

  import Plug.Conn
  @behaviour Plug

  @cookie_name "_app_session"
  @cookie_opts [
    http_only: true,
    secure: true,
    same_site: "Strict",
    max_age: 86_400
  ]

  @impl true
  def init(opts), do: opts

  @impl true
  def call(conn, _opts) do
    session =
      conn
      |> fetch_cookies()
      |> get_session_from_cookie()

    conn
    |> assign(:session, session)
    |> register_before_send(&persist_session/1)
  end

  defp get_session_from_cookie(conn) do
    case conn.cookies[@cookie_name] do
      nil ->
        {:ok, session} = SessionManager.new()
        session

      cookie_value ->
        case Base.url_decode64(cookie_value) do
          {:ok, binary} ->
            case SessionManager.deserialize(binary) do
              {:ok, session} ->
                session

              {:error, _reason} ->
                {:ok, session} = SessionManager.new()
                session
            end

          :error ->
            {:ok, session} = SessionManager.new()
            session
        end
    end
  end

  defp persist_session(conn) do
    session = conn.assigns[:session]

    if session do
      case SessionManager.serialize(session) do
        {:ok, binary} ->
          encoded = Base.url_encode64(binary)
          put_resp_cookie(conn, @cookie_name, encoded, @cookie_opts)

        {:error, _reason} ->
          delete_resp_cookie(conn, @cookie_name)
      end
    else
      conn
    end
  end
end

